func (_q *UnitQuery) loadMaterials(ctx context.Context, query *MaterialQuery, nodes []*Unit, init func(*Unit), assign func(*Unit, *Material)) error {
	fks := make([]driver.Value, 0, len(nodes))
	nodeids := make(map[int]*Unit)
	for i := range nodes {
		fks = append(fks, nodes[i].ID)
		nodeids[nodes[i].ID] = nodes[i]
		if init != nil {
			init(nodes[i])
		}
	}
	if len(query.ctx.Fields) > 0 {
		query.ctx.AppendFieldOnce(material.FieldDefaultUnitID)
	}
	query.Where(predicate.Material(func(s *sql.Selector) {
		s.Where(sql.InValues(s.C(unit.MaterialsColumn), fks...))
	}))
	neighbors, err := query.All(ctx)
	if err != nil {
		return err
	}
	for _, n := range neighbors {
		fk := n.DefaultUnitID
		node, ok := nodeids[fk]
		if !ok {
			return fmt.Errorf(`unexpected referenced foreign-key "default_unit_id" returned %v for node %v`, fk, n.ID)
		}
		assign(node, n)
	}
	return nil
}
